// src/components/Player.js
import React, { useState, useEffect } from "react";
import { View, Text, Image } from "react-native";

/**
 * Componente Player com animação de sprite sheet 4x4
 * (4 direções × 4 frames de movimento)
 */
export default function Player({
    x,
    y,
    direction = "down",
    character = "‍",
    isMoving = false,
    useImage = false,
}) {
    const [frameIndex, setFrameIndex] = useState(0);

    // Animação: cicla entre 4 frames
    useEffect(() => {
        if (!isMoving) {
            setFrameIndex(0);
            return;
        }

        const animationInterval = setInterval(() => {
            setFrameIndex((prev) => (prev + 1) % 4);
        }, 100); // 100ms por frame

        return () => clearInterval(animationInterval);
    }, [isMoving]);

    if (useImage) {
        // Sprite sheet 4x4: 4 direções (rows) × 4 frames (columns)
        const FRAME_SIZE = 32; // Tamanho de cada frame em pixels

        // Mapa de direções para linha na sprite sheet
        const directionRowMap = {
            up: 0,       // Linha 0
            left: 1,     // Linha 1
            down: 2,     // Linha 2 (padrão)
            right: 3,    // Linha 3
        };

        const rowIndex = directionRowMap[direction] || 2; // down é padrão

        // Calcula o offset para mostrar o frame correto
        const offsetX = -frameIndex * FRAME_SIZE;
        const offsetY = -rowIndex * FRAME_SIZE;

        return (
            <View
                style={{
                    position: "absolute",
                    left: x,
                    top: y,
                    width: FRAME_SIZE,
                    height: FRAME_SIZE,
                    overflow: "hidden", // Esconde o resto da sprite sheet
                    borderRadius: 2,
                }}
            >
                <Image
                    source={require("../../assets/images/player.png")}
                    style={{
                        // Tamanho total da sprite sheet: 128×128 (4×4 com frames de 32px)
                        width: FRAME_SIZE * 4,   // 4 colunas (frames)
                        height: FRAME_SIZE * 4,  // 4 linhas (direções)
                        marginLeft: offsetX,
                        marginTop: offsetY,
                    }}
                />
            </View>
        );
    }

    // Fallback para emoji
    return (
        <View
            style={{
                position: "absolute",
                left: x,
                top: y,
                width: 40,
                height: 40,
                justifyContent: "center",
                alignItems: "center",
                borderRadius: 20,
                backgroundColor: "rgba(100, 150, 255, 0.3)",
                opacity: isMoving && frameIndex % 2 === 0 ? 0.7 : 1,
            }}
        >
            <Text style={{ fontSize: 32 }}>{character}</Text>
        </View>
    );
}

// src/components/Player.js
import React, { useState, useEffect } from "react";
import { View, Text, Image } from "react-native";

/**
 * Componente Player com animação de sprite sheet 4x4
 * (4 direções × 4 frames de movimento)
 */
export default function Player({
    x,
    y,
    direction = "down",
    character = "‍",
    isMoving = false,
    useImage = false,
}) {
    const [frameIndex, setFrameIndex] = useState(0);

    // Animação: cicla entre 4 frames
    useEffect(() => {
        if (!isMoving) {
            setFrameIndex(0);
            return;
        }

        const animationInterval = setInterval(() => {
            setFrameIndex((prev) => (prev + 1) % 4);
        }, 100); // 100ms por frame

        return () => clearInterval(animationInterval);
    }, [isMoving]);

    if (useImage) {
        // Sprite sheet 4x4: 4 direções (rows) × 4 frames (columns)
        const FRAME_SIZE = 32; // Tamanho de cada frame na sprite sheet (em pixels)
        const DISPLAY_SIZE = 40; // Tamanho de exibição no jogo (em pixels)
        const SCALE = DISPLAY_SIZE / FRAME_SIZE; // Escala para ampliar

        // Mapa de direções para linha na sprite sheet
        const directionRowMap = {
            up: 0,       // Linha 0
            left: 1,     // Linha 1
            down: 2,     // Linha 2 (padrão)
            right: 3,    // Linha 3
        };

        const rowIndex = directionRowMap[direction] || 2; // down é padrão

        // Calcula o offset para mostrar o frame correto
        const offsetX = -frameIndex * FRAME_SIZE * SCALE;
        const offsetY = -rowIndex * FRAME_SIZE * SCALE;

        return (
            <View
                style={{
                    position: "absolute",
                    left: x,
                    top: y,
                    width: DISPLAY_SIZE,
                    height: DISPLAY_SIZE,
                    overflow: "hidden", // Esconde o resto da sprite sheet
                    borderRadius: 2,
                }}
            >
                <Image
                    source={require("../../assets/images/player.png")}
                    style={{
                        // Tamanho total da sprite sheet escalado
                        width: FRAME_SIZE * 4 * SCALE,   // 4 colunas × escala
                        height: FRAME_SIZE * 4 * SCALE,  // 4 linhas × escala
                        marginLeft: offsetX,
                        marginTop: offsetY,
                    }}
                />
            </View>
        );
    }

    // Fallback para emoji
    return (
        <View
            style={{
                position: "absolute",
                left: x,
                top: y,
                width: 40,
                height: 40,
                justifyContent: "center",
                alignItems: "center",
                borderRadius: 20,
                backgroundColor: "rgba(100, 150, 255, 0.3)",
                opacity: isMoving && frameIndex % 2 === 0 ? 0.7 : 1,
            }}
        >
            <Text style={{ fontSize: 32 }}>{character}</Text>
        </View>
    );
}
